// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @dev Interfaccia minima del ProofManager usata dal Coordinator.
interface IProofManager {
    function getProofIfExists(bytes32 infoHash)
        external
        view
        returns (bool exists, bytes32 proofHash);
}

/// @title Coordinator per zk-oracle prototype
/// @notice Riceve richieste dal client, interroga il ProofManager
///         e coordina la restituzione dei risultati.
contract Coordinator {
    enum Status {
        None,
        Pending,
        ProofFound,
        Error
    }

    struct VerificationRequest {
        address requester;   // chi ha richiesto la verifica (client)
        bytes32 infoHash;    // identificatore della "conformità" da verificare
        Status status;
        bytes32 proofHash;   // riferimento alla prova (hash, id, ecc.)
        string error;        // eventuale motivo di errore
    }

    /// @notice Indirizzo del ProofManager
    address public proofManager;

    /// @dev contatore per assegnare ID univoci alle richieste
    uint256 public nextRequestId;

    /// @dev mappatura requestId -> struct di richiesta
    mapping(uint256 => VerificationRequest) public requests;

    /// @notice Emesso quando una nuova richiesta viene aperta
    event VerificationRequested(
        uint256 indexed requestId,
        address indexed requester,
        bytes32 infoHash
    );

    /// @notice Emesso quando una prova viene trovata (o recuperata)
    event ProofFound(
        uint256 indexed requestId,
        bytes32 proofHash
    );

    /// @notice Emesso in caso di errore nel processo di verifica
    event VerificationError(
        uint256 indexed requestId,
        string reason
    );

    modifier onlyProofManager() {
        require(msg.sender == proofManager, "Coordinator: not ProofManager");
        _;
    }

    constructor(address _proofManager) {
        require(_proofManager != address(0), "Coordinator: zero address");
        proofManager = _proofManager;
    }

    /// @notice Il client richiede una verifica per una certa infoHash
    /// @param infoHash identificatore (es. hash dei parametri di conformita')
    /// @return requestId ID univoco della richiesta
    function requestVerification(bytes32 infoHash)
        external
        returns (uint256 requestId)
    {
        requestId = nextRequestId++;

        VerificationRequest storage req = requests[requestId];
        req.requester = msg.sender;
        req.infoHash = infoHash;
        req.status = Status.Pending;

        emit VerificationRequested(requestId, msg.sender, infoHash);

        // 1) Controllo sincrono se la prova esiste gia'
        (bool exists, bytes32 proofHash) =
            IProofManager(proofManager).getProofIfExists(infoHash);

        if (exists) {
            // Caso "La prova e' stata gia' generata"
            req.status = Status.ProofFound;
            req.proofHash = proofHash;

            emit ProofFound(requestId, proofHash);
            // In questo caso l'oracolo non deve fare nulla:
            // il client puo' gia' leggere il risultato.
        }

        // 2) Se non esiste, la richiesta resta Pending:
        // l'oracolo off-chain ascoltera' l'evento VerificationRequested
        // e iniziera' il processo di generazione della prova.
    }

    /// @notice Chiamata dal ProofManager quando la prova e' disponibile
    /// @param requestId ID della richiesta a cui associare la prova
    /// @param proofHash riferimento alla prova (hash)
    function notifyProof(uint256 requestId, bytes32 proofHash)
        external
        onlyProofManager
    {
        VerificationRequest storage req = requests[requestId];
        require(req.status == Status.Pending, "Coordinator: not pending");

        req.status = Status.ProofFound;
        req.proofHash = proofHash;

        emit ProofFound(requestId, proofHash);
    }

    /// @notice Chiamata dal ProofManager in caso di errore nella verifica
    /// @param requestId ID della richiesta
    /// @param reason testo da usare come motivo di errore
    function notifyError(uint256 requestId, string calldata reason)
        external
        onlyProofManager
    {
        VerificationRequest storage req = requests[requestId];
        require(req.status == Status.Pending, "Coordinator: not pending");

        req.status = Status.Error;
        req.error = reason;

        emit VerificationError(requestId, reason);
    }

    /// @notice Restituisce tutti i dettagli di una richiesta
    function getRequest(uint256 requestId)
        external
        view
        returns (
            address requester,
            bytes32 infoHash,
            Status status,
            bytes32 proofHash,
            string memory error
        )
    {
        VerificationRequest storage req = requests[requestId];
        return (req.requester, req.infoHash, req.status, req.proofHash, req.error);
    }
}
